let str: string = ""

for (let i: number = 0; i < 3; i++) {
  for (let j: number = 0; j < 6; j++) {
    if (i % 3 < 1) {
      str = str + "||"
    } else if (i % 3 < 2) {
      str = str + "KU"
    } else if (i % 3 == 2) {
      str = str + ".TSU"
    } else {
      str = str + "TA"
    }
  }
  str = str + "\n" // quebra a linha
}

console.log(str)
